@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="chat-app">
    @* ── Left Sidebar: Channel List ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h2>Channels</h2>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <section class="message-area @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h3># @_activeChannel.Name</h3>
                <span class="channel-description">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="_messageListRef">
                @if (_loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_allOlderLoaded)
                {
                    <div class="history-start">Beginning of conversation</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-bubble" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-meta">
                                <strong class="message-author">@msg.Author</strong>
                                <span class="message-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-content">@msg.Content</div>

                            @* Reactions *@
                            @if (msg.Reactions?.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var reaction in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", reaction.Users)"
                                                @onclick="() => AddReactionAsync(msg.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @* Thread replies link *@
                            @if (GetThreadSummary(msg.Id) is { } thread)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    💬 @thread.ReplyCount @(thread.ReplyCount == 1 ? "reply" : "replies")
                                </button>
                            }

                            @* Hover action buttons *@
                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg)">
                                        💬 Reply
                                    </button>
                                    <button class="action-btn" title="Add reaction"
                                            @onclick="() => ToggleEmojiPicker(msg.Id)">
                                        😀 React
                                    </button>
                                </div>

                                @if (_emojiPickerMessageId == msg.Id)
                                {
                                    <div class="emoji-picker">
                                        @foreach (var emoji in _commonEmojis)
                                        {
                                            <button class="emoji-option"
                                                    @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                @emoji
                                            </button>
                                        }
                                    </div>
                                }
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Type a message…"
                          @bind="_newMessageText" @bind:event="oninput"
                          @onkeydown="HandleMainKeyDown" />
                <button class="send-btn" @onclick="SendMainMessageAsync"
                        disabled="@string.IsNullOrWhiteSpace(_newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right Panel: Thread View ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>
            <div class="thread-root-quote">
                <strong>@_threadRootMessage.Author</strong>
                <span class="message-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                <p>@_threadRootMessage.Content</p>
            </div>
            <div class="thread-messages" @ref="_threadListRef">
                @if (_threadReplies is not null)
                {
                    @foreach (var reply in _threadReplies)
                    {
                        <div class="message-bubble thread-reply">
                            <div class="message-meta">
                                <strong class="message-author">@reply.Author</strong>
                                <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>
                            @if (reply.Reactions?.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var reaction in reply.Reactions)
                                    {
                                        <button class="reaction-badge"
                                                title="@string.Join(", ", reaction.Users)"
                                                @onclick="() => AddReactionAsync(reply.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>
            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Reply in thread…"
                          @bind="_threadReplyText" @bind:event="oninput"
                          @onkeydown="HandleThreadKeyDown" />
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(_threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 50;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "👀"];

    // Data
    private List<Channel>? _channels;
    private List<Message>? _messages;
    private List<Message>? _threadReplies;
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    // State
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private string _newMessageText = "";
    private string _threadReplyText = "";
    private int _skip;
    private bool _loadingOlder;
    private bool _allOlderLoaded;

    // Element references for scroll management
    private ElementReference _messageListRef;
    private ElementReference _threadListRef;

    // JS module
    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<Chat>? _dotNetRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _jsModule = await JS.InvokeAsync<IJSObjectReference>("import",
                "./Components/Pages/Chat.razor.js");
        }
    }

    // ── Channel selection ──

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _skip = 0;
        _allOlderLoaded = false;
        _messages = new();
        _emojiPickerMessageId = null;
        CloseThread();

        await LoadMessagesAsync();
        await ChatService.MarkChannelReadAsync(channel.Id);
        await RefreshChannelsAsync();
        await ScrollToBottomAsync();
        await SetupScrollWatcherAsync();
    }

    private async Task RefreshChannelsAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    // ── Message loading & pagination ──

    private async Task LoadMessagesAsync()
    {
        var fetched = await ChatService.GetMessagesAsync(_activeChannelId!.Value, _skip, PageSize);
        if (fetched.Count < PageSize) _allOlderLoaded = true;
        _messages!.InsertRange(0, fetched);
        _skip += fetched.Count;
        await BuildThreadSummariesAsync();
    }

    [JSInvokable]
    public async Task LoadOlderMessages()
    {
        if (_loadingOlder || _allOlderLoaded || _activeChannelId is null) return;
        _loadingOlder = true;
        StateHasChanged();

        var fetched = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (fetched.Count < PageSize) _allOlderLoaded = true;
        _messages!.InsertRange(0, fetched);
        _skip += fetched.Count;
        await BuildThreadSummariesAsync();

        _loadingOlder = false;
        StateHasChanged();
    }

    // ── Thread summaries ──

    private Task BuildThreadSummariesAsync()
    {
        _threadSummaries.Clear();
        if (_messages is null) return Task.CompletedTask;

        var replyGroups = _messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in replyGroups)
        {
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }

        return Task.CompletedTask;
    }

    private ThreadSummary? GetThreadSummary(int messageId)
    {
        return _threadSummaries.GetValueOrDefault(messageId);
    }

    // ── Sending messages ──

    private async Task SendMainMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _messages!.Add(sent);
        _skip++;
        _newMessageText = "";
        await BuildThreadSummariesAsync();
        await ScrollToBottomAsync();
    }

    private async Task HandleMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMainMessageAsync();
        }
    }

    // ── Thread ──

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadOpen = true;
        _threadReplyText = "";
        _emojiPickerMessageId = null;
        _threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
        StateHasChanged();
        await ScrollThreadToBottomAsync();
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
        _threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootMessage is null || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(
            _activeChannelId.Value, _threadReplyText.Trim(), _threadRootMessage.Id);
        _threadReplies!.Add(sent);
        _messages!.Add(sent);
        _skip++;
        _threadReplyText = "";
        await BuildThreadSummariesAsync();
        await ScrollThreadToBottomAsync();
    }

    private async Task HandleThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Reactions ──

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        _emojiPickerMessageId = null;
        await ChatService.AddReactionAsync(messageId, emoji);

        // Refresh the messages to show updated reactions
        if (_activeChannelId is not null)
        {
            var oldSkip = _skip;
            _skip = 0;
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, oldSkip);
            _skip = oldSkip;
            await BuildThreadSummariesAsync();

            if (_threadOpen && _threadRootMessage is not null)
            {
                _threadReplies = await ChatService.GetThreadAsync(_threadRootMessage.Id);
                _threadRootMessage = _messages.FirstOrDefault(m => m.Id == _threadRootMessage.Id)
                                     ?? _threadRootMessage;
            }
        }
    }

    // ── Formatting helpers ──

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? description[..37] + "…" : description;
    }

    // ── JS interop for scrolling ──

    private async Task ScrollToBottomAsync()
    {
        try
        {
            await Task.Yield(); // let render complete
            if (_jsModule is not null)
                await _jsModule.InvokeVoidAsync("scrollToBottom", _messageListRef);
        }
        catch (JSDisconnectedException) { }
    }

    private async Task ScrollThreadToBottomAsync()
    {
        try
        {
            await Task.Yield();
            if (_jsModule is not null)
                await _jsModule.InvokeVoidAsync("scrollToBottom", _threadListRef);
        }
        catch (JSDisconnectedException) { }
    }

    private async Task SetupScrollWatcherAsync()
    {
        try
        {
            if (_jsModule is not null && _dotNetRef is not null)
                await _jsModule.InvokeVoidAsync("watchScrollTop", _messageListRef, _dotNetRef);
        }
        catch (JSDisconnectedException) { }
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            if (_jsModule is not null)
            {
                await _jsModule.InvokeVoidAsync("dispose");
                await _jsModule.DisposeAsync();
            }
        }
        catch (JSDisconnectedException) { }

        _dotNetRef?.Dispose();
    }
}

export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

let _observer = null;
let _element = null;

export function watchScrollTop(element, dotNetRef) {
    dispose();
    _element = element;
    if (!element) return;

    element.addEventListener('scroll', handleScroll);

    function handleScroll() {
        if (element.scrollTop === 0) {
            dotNetRef.invokeMethodAsync('LoadOlderMessages');
        }
    }

    _observer = { element, handleScroll };
}

export function dispose() {
    if (_observer) {
        _observer.element.removeEventListener('scroll', _observer.handleScroll);
        _observer = null;
    }
}

/* ── Chat App Layout ── */

.chat-app {
    display: flex;
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    font-family: 'Segoe UI', -apple-system, BlinkMacSystemFont, sans-serif;
    color: #1d1c1d;
    background: #fff;
}

/* ── Channel Sidebar ── */

.channel-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.sidebar-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
    font-weight: 700;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 6px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 0 8px;
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 4px;
    position: relative;
    transition: background 0.15s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.1);
}

.channel-item.active {
    background: #1264a3;
    color: #fff;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    flex: 1;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-desc {
    width: 100%;
    font-size: 0.75rem;
    opacity: 0.7;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
    position: absolute;
    right: 8px;
    top: 8px;
}

/* ── Main Message Area ── */

.message-area {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #e1e1e1;
    transition: flex 0.2s;
}

.message-area.expanded {
    border-right: none;
}

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e1e1e1;
    background: #fff;
    flex-shrink: 0;
}

.message-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
}

.channel-description {
    font-size: 0.85rem;
    color: #616061;
    margin-top: 2px;
    display: block;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 20px;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.loading-indicator,
.history-start {
    text-align: center;
    padding: 8px;
    font-size: 0.8rem;
    color: #999;
}

.message-bubble {
