    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 11;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    padding: 4px 6px;
    cursor: pointer;
    border-radius: 4px;
    transition: background 0.1s;
}

.emoji-option:hover {
    background: #f0f0f0;
}

/* Message input */

.message-input-area {
    padding: 12px 20px;
    border-top: 1px solid #e1e1e1;
    display: flex;
    gap: 8px;
    align-items: flex-end;
    background: #fff;
    flex-shrink: 0;
}

.message-input {
    flex: 1;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    resize: none;
    outline: none;
    transition: border-color 0.15s;
}

.message-input:focus {
    border-color: #1264a3;
}

.send-btn {
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 8px 20px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background: #005e44;
}

.send-btn:disabled {
    background: #ccc;
    cursor: default;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 1.1rem;
}

/* ── Thread Panel ── */

.thread-panel {
    width: 25%;
    min-width: 280px;
    max-width: 420px;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-left: 1px solid #e1e1e1;
}

.thread-header {
    padding: 12px 16px;
    border-bottom: 1px solid #e1e1e1;
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-thread-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    color: #666;
}

.close-thread-btn:hover {
    background: #f0f0f0;
    color: #333;
}

.thread-root-quote {
    padding: 12px 16px;
    background: #f8f8f8;
    border-bottom: 1px solid #e1e1e1;
