export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

let _observer = null;
let _element = null;

export function watchScrollTop(element, dotNetRef) {
    dispose();
    _element = element;
    if (!element) return;

    element.addEventListener('scroll', handleScroll);

    function handleScroll() {
        if (element.scrollTop === 0) {
            dotNetRef.invokeMethodAsync('LoadOlderMessages');
        }
    }

    _observer = { element, handleScroll };
}

export function dispose() {
    if (_observer) {
        _observer.element.removeEventListener('scroll', _observer.handleScroll);
        _observer = null;
    }
}

